# !pip install -U ultralytics

import cv2
import matplotlib.pyplot as plt
from ultralytics import YOLO

model = YOLO("yolo12n.pt")
img_path = "/content/data/person_car.jpg"
# 실제박스와 예측박스 겹치는 정도 50%
results = model(img_path, conf=0.5) # 50%이상 IOU값 박스의 일치 정도 실제박스위치/예측된 위치
result = results[0]
count = {}

for box in result.boxes:
  class_id = int(box.cls[0]) # class
  score = float(box.conf[0]) # confidence
  name = model.names[class_id] # 자학습하면서 이름을 모델에 저장
  count[name] = count.get(name, 0) + 1
print(count)

# 시각화
draw_img = result.plot()
darw_img_rgb = cv2.cvtColor(draw_img, cv2.COLOR_BGR2RGB)
plt.figure(figsize =(12,12))
plt.imshow(darw_img_rgb)
plt.axis("off")
plt.show

