from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser
# 창의성 :0 같은 답변, 0~2조절(1이전 값)
llm = ChatOpenAI(model_name = "gpt-4o", temperature = 0) # llm연결
prompt = ChatPromptTemplate.from_template(
    "다음 텍스트에 대한 완벽한 답변을 한 문장으로 제공해 주세요. 텍스트: {text}"
)

output_parser = StrOutputParser() # 모델만 사용하는 meta정보들을 제거하고 문자열로 변환
if llm is not None:
  chain = prompt | llm | output_parser # chain을 정
  # LLM호출
  response = chain.invoke({"text": "라따뚜이에 어울리는 와인에 어떤 것들이 있을까요?"})
  print(response)

else:
  print("Chain 실행 건너띔: LLM 객체를 초기화할 수 없습니다.")

