# tool 사용
from langchain_core.tools import tool
from langchain_core.messages import HumanMessage
from langchain_openai import ChatOpenAI
from langgraph.prebuilt import create_react_agent # 내부적으로 langgraph 생성
import datetime,random

# !pip install -q -U ddgs

from langchain_community.tools import DuckDuckGoSearchRun
web_search_engine = DuckDuckGoSearchRun()

# DB쿼리, 파일로딩 ------> 포함
@tool
def search_web(query: str) -> str:
    "최신정보를 검색합니다."
    try:
        print(f"[Tool Log] '{query}'에 대해 실제 웹 검색을 수행 중...")
        search_result = web_search_engine.invoke(query)
        return search_result
    except Exception as e:
        return f"검색 중 오류가 발생했습니다: {str(e)}"
@tool
def get_current_time() -> str:
    "최신정보를 검색합니다."
    now = datetime.datetime.now()
    return f"현재 시각: {now.strftime('%Y년 %m월 %d일 %H시 %M분')}"

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
tools = [search_web, get_current_time] # 여러개의 툴등록용
# llm에서 사용할 툴을 등록
agent = create_react_agent(llm, tools)

queries = [
    "현재 몇 시야? 그리고 요즘 AI 트렌드는 어때?",
    "Python 최신 버전의 주요 변경사항을 알려줘",
]

for query in queries:
    print(f"? 질문: {query}")
    print(f"{'='*55}")
    result = agent.invoke({"messages": [HumanMessage(content=query)]})
    for msg in result["messages"]:
        if hasattr(msg, "tool_calls") and msg.tool_calls:
            for tc in msg.tool_calls:
                print(f"  🔧 Tool 호출: {tc['name']}({tc['args']})")
        elif msg.__class__.__name__ == "ToolMessage":
            print(f" Tool 결과: {msg.content[:80]}...")

    print(f"\n 최종 답변:\n{result['messages'][-1].content}")

